return [{
  json: {
    dict: {
      applicant: {
        firstName: 'Max',
        lastName: 'Mustermann',
        email: 'max.mustermann@email.de',
        emailRepeat: 'max.mustermann@email.de',
        phone: '+4917612345678',
        role: '0'
      },
      member: {
        firstName: 'Max',
        lastName: 'Mustermann',
        street: 'Musterstrasse 1',
        zip: '63739',
        city: 'Aschaffenburg',
        birthDate: '01.01.2010',
        entryDate: '01.01.2026',
        salutationValue: '2',
        titleValue: '',
        countryValue: 'DE',
        genderValue: '1',
        familyStatusValue: '1'
      },
      communication: {
        description: 'Privat',
        email: 'max.mustermann@email.de',
        phone: '',
        mobile: '+4917612345678'
      },
      departments: [],
      bank: {
        accountHolder: 'Max Mustermann',
        iban: 'DE89370400440532013000',
        bic: ''
      },
      declarations: {
        sepaMandate: true,
        privacy: true,
        consent: true,
        statutes: true
      },
      captchaToken: '',
      captchaSolver: {
        enabled: false
      }
    }
  }
}];

const rawInput = $json;

function pickObject(value) {
  return value && typeof value === 'object' && !Array.isArray(value);
}

const input = pickObject(rawInput?.dict)
  ? rawInput.dict
  : pickObject(rawInput?.payload)
    ? rawInput.payload
    : pickObject(rawInput?.data)
      ? rawInput.data
      : rawInput;

if (!pickObject(input)) {
  throw new Error('Input muss ein JSON-Objekt (dict) sein. Optional als dict, payload oder data uebergeben.');
}

function get(path) {
  return path.split('.').reduce((acc, key) => (acc == null ? undefined : acc[key]), input);
}

const requiredPaths = [
  'applicant.firstName',
  'applicant.lastName',
  'applicant.email',
  'applicant.emailRepeat',
  'applicant.phone',
  'member.firstName',
  'member.lastName',
  'member.street',
  'member.zip',
  'member.city',
  'member.birthDate',
  'member.entryDate',
  'member.salutationValue',
  'member.countryValue',
  'member.genderValue',
  'member.familyStatusValue',
  'communication.email',
  'communication.mobile',
  'bank.accountHolder',
  'bank.iban'
];

const missing = requiredPaths.filter((p) => {
  const v = get(p);
  return v === undefined || v === null || String(v).trim() === '';
});

const email = String(get('applicant.email') || '').trim();
const emailRepeat = String(get('applicant.emailRepeat') || '').trim();
const iban = String(get('bank.iban') || '').replace(/\s+/g, '').toUpperCase();

const formatErrors = [];
if (email && emailRepeat && email !== emailRepeat) {
  formatErrors.push('applicant.email und applicant.emailRepeat muessen identisch sein.');
}
if (iban && !/^[A-Z]{2}[0-9A-Z]{13,32}$/.test(iban)) {
  formatErrors.push('bank.iban hat ein ungueltiges Format.');
}

if (missing.length || formatErrors.length) {
  throw new Error(
    [
      missing.length ? `Fehlende Pflichtfelder: ${missing.join(', ')}` : '',
      formatErrors.length ? `Formatfehler: ${formatErrors.join(' | ')}` : ''
    ]
      .filter(Boolean)
      .join(' || ')
  );
}

const normalized = {
  applicant: {
    firstName: String(input.applicant.firstName).trim(),
    lastName: String(input.applicant.lastName).trim(),
    email,
    emailRepeat,
    phone: String(input.applicant.phone).trim(),
    role: String(input.applicant.role ?? '0')
  },
  member: {
    firstName: String(input.member.firstName).trim(),
    lastName: String(input.member.lastName).trim(),
    street: String(input.member.street).trim(),
    zip: String(input.member.zip).trim(),
    city: String(input.member.city).trim(),
    birthDate: String(input.member.birthDate).trim(),
    entryDate: String(input.member.entryDate).trim(),
    salutationValue: String(input.member.salutationValue).trim(),
    titleValue: input.member.titleValue == null ? '' : String(input.member.titleValue).trim(),
    countryValue: String(input.member.countryValue).trim(),
    genderValue: String(input.member.genderValue).trim(),
    familyStatusValue: String(input.member.familyStatusValue).trim()
  },
  communication: {
    description: String(input.communication.description ?? 'Privat').trim(),
    email: String(input.communication.email).trim(),
    phone: String(input.communication.phone ?? '').trim(),
    mobile: String(input.communication.mobile).trim()
  },
  departments: Array.isArray(input.departments) ? input.departments.map((v) => String(v)) : [],
  bank: {
    accountHolder: String(input.bank.accountHolder).trim(),
    iban: iban,
    bic: String(input.bank.bic ?? '').trim()
  },
  declarations: {
    sepaMandate: input.declarations?.sepaMandate !== false,
    privacy: input.declarations?.privacy !== false,
    consent: input.declarations?.consent !== false,
    statutes: input.declarations?.statutes !== false
  },
  captchaToken: input.captchaToken ? String(input.captchaToken).trim() : '',
  captchaSolver: input.captchaSolver ?? {}
};

return [{ json: normalized }];

const data = $('Validate Mandatory Inputs').item.json;
const antragConfig = $('Set Antrag Config').item.json;

const START_URL = String(antragConfig.startUrl || '').trim();
const FORM_URL = String(antragConfig.formUrl || '').trim();
const httpRequest = this.helpers.httpRequest.bind(this.helpers);

if (!START_URL || !FORM_URL) {
  throw new Error('workflow_error: startUrl/formUrl fehlen in Set Antrag Config.');
}

function parseSetCookie(cookieLine) {
  const first = String(cookieLine || '').split(';')[0];
  const idx = first.indexOf('=');
  if (idx === -1) return null;
  return {
    name: first.slice(0, idx).trim(),
    value: first.slice(idx + 1).trim()
  };
}

function cookieHeader(jar) {
  return Object.entries(jar)
    .map(([k, v]) => `${k}=${v}`)
    .join('; ');
}

function extractSetCookies(headers) {
  const raw = headers?.['set-cookie'] ?? headers?.['Set-Cookie'];
  if (!raw) return [];
  return Array.isArray(raw) ? raw : [String(raw)];
}

function toFormUrlEncoded(form) {
  return Object.entries(form || {})
    .map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(v == null ? '' : String(v))}`)
    .join('&');
}

function shortHtmlSnippet(html) {
  return String(html || '')
    .replace(/\s+/g, ' ')
    .slice(0, 260);
}

function ensureHttpOk(response, label) {
  const status = Number(response?.status || 0);
  if (!Number.isFinite(status) || status < 200 || status >= 400) {
    const snippet = shortHtmlSnippet(response?.text);
    throw new Error(`${label} fehlgeschlagen: HTTP ${status}, snippet=${snippet}`);
  }
}

async function requestHtml({ method, url, form, jar }) {
  const headers = {
    'User-Agent': 'n8n-tsv-aschach-workflow/1.0',
    Accept: 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8'
  };

  const cookie = cookieHeader(jar);
  if (cookie) headers.Cookie = cookie;

  const options = {
    method,
    url,
    headers,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  };

  if (form) {
    headers['Content-Type'] = 'application/x-www-form-urlencoded';
    options.body = toFormUrlEncoded(form);
  }

  const response = await httpRequest(options);
  const setCookies = extractSetCookies(response.headers);
  for (const line of setCookies) {
    const parsed = parseSetCookie(line);
    if (parsed) jar[parsed.name] = parsed.value;
  }

  const text = typeof response.body === 'string' ? response.body : String(response.body || '');
  return {
    status: Number(response.statusCode || 0),
    text,
    finalUrl: response.request?.res?.responseUrl || response.request?.href || url
  };
}

function activeStep(html) {
  const m = html.match(/<li class="active">([\s\S]*?)<\/li>/i);
  if (!m) return 'unknown';
  return m[1].replace(/<[^>]+>/g, '').trim();
}

function hiddenFields(html) {
  const out = {};
  const re = /<input[^>]*type="hidden"[^>]*name="([^"]+)"[^>]*value="([^"]*)"[^>]*>/gi;
  let m;
  while ((m = re.exec(html)) !== null) {
    out[m[1]] = m[2];
  }
  return out;
}

function firstSelectableOption(html, selectName) {
  const escaped = selectName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const blockRe = new RegExp(`<select[^>]*name="${escaped}"[^>]*>([\\s\\S]*?)<\\/select>`, 'i');
  const block = html.match(blockRe);
  if (!block) return '';

  const optionRe = /<option([^>]*)>/gi;
  let selected = '';
  let fallback = '';
  let m;
  while ((m = optionRe.exec(block[1])) !== null) {
    const attrs = m[1];
    const vm = attrs.match(/value="([^"]*)"/i);
    const value = vm ? vm[1] : '';
    if (!fallback && value !== '') fallback = value;
    if (/\bselected\b/i.test(attrs)) {
      selected = value;
      break;
    }
  }
  return selected || fallback;
}

const jar = {};

let page = await requestHtml({ method: 'GET', url: START_URL, jar });
ensureHttpOk(page, 'Initialer Seitenaufruf');
let hidden = hiddenFields(page.text);

let payload = {
  ...hidden,
  strVorname: data.applicant.firstName,
  strNachname: data.applicant.lastName,
  strEmail: data.applicant.email,
  strEmail2: data.applicant.emailRepeat,
  strTelefono: data.applicant.phone,
  Antragsteller: data.applicant.role || '0',
  iOperation: '1'
};

page = await requestHtml({ method: 'POST', url: FORM_URL, form: payload, jar });
ensureHttpOk(page, 'Schritt 1');
if (activeStep(page.text) !== 'Mitgliedsdaten') {
  throw new Error(`Schritt 1 fehlgeschlagen, aktiver Schritt: ${activeStep(page.text)}`);
}

hidden = hiddenFields(page.text);
const titleValue = data.member.titleValue || firstSelectableOption(page.text, 'aAdressdaten[4]') || '';

payload = {
  ...hidden,
  'aAdressdaten[Vorname]': data.member.firstName,
  'aAdressdaten[Nachname]': data.member.lastName,
  'aAdressdaten[Strasse]': data.member.street,
  'aAdressdaten[Plz]': data.member.zip,
  'aAdressdaten[Ort]': data.member.city,
  Geburtsdatum: data.member.birthDate,
  Vereinseintrittsdatum: data.member.entryDate,
  'aAdressdaten[2]': data.member.salutationValue,
  'aAdressdaten[4]': titleValue,
  'aAdressdaten[Land]': data.member.countryValue,
  'aAdressdaten[Geschlecht]': data.member.genderValue,
  'aAdressdaten[6]': data.member.familyStatusValue,
  'aKom[1][Beschreibung]': data.communication.description || 'Privat',
  'aKom[1][7]': data.communication.email,
  'aKom[1][8]': data.communication.phone || '',
  'aKom[1][9]': data.communication.mobile,
  iOperation: '1'
};

if (Array.isArray(data.departments)) {
  for (const dep of data.departments) {
    payload[`aAbt[${dep}]`] = String(dep);
  }
}

page = await requestHtml({ method: 'POST', url: FORM_URL, form: payload, jar });
ensureHttpOk(page, 'Schritt 2');
if (activeStep(page.text) !== 'Zahlungsart') {
  throw new Error(`Schritt 2 fehlgeschlagen, aktiver Schritt: ${activeStep(page.text)}`);
}

hidden = hiddenFields(page.text);
payload = {
  ...hidden,
  iZahlungsart: '4',
  'aBankData[Kontoinhaber]': data.bank.accountHolder,
  'aBankData[IBAN]': data.bank.iban,
  iOperation: '1'
};

if (data.bank.bic) payload['aBankData[BIC]'] = data.bank.bic;
if (data.declarations.sepaMandate) payload['Text[11]'] = '1';

page = await requestHtml({ method: 'POST', url: FORM_URL, form: payload, jar });
ensureHttpOk(page, 'Schritt 3');
if (activeStep(page.text) !== 'Zusatzdaten') {
  throw new Error(`Schritt 3 fehlgeschlagen, aktiver Schritt: ${activeStep(page.text)}`);
}

hidden = hiddenFields(page.text);
payload = {
  ...hidden,
  iOperation: '1'
};
if (data.declarations.privacy) payload['aTexts[13]'] = '1';
if (data.declarations.consent) payload['aTexts[14]'] = '1';
if (data.declarations.statutes) payload['aTexts[5733]'] = '1';

page = await requestHtml({ method: 'POST', url: FORM_URL, form: payload, jar });
ensureHttpOk(page, 'Schritt 4');
if (activeStep(page.text) !== 'Kontrolle/Absenden') {
  throw new Error(`Schritt 4 fehlgeschlagen, aktiver Schritt: ${activeStep(page.text)}`);
}

return [{
  json: {
    data,
    jar,
    formUrl: FORM_URL,
    pageAfterStep4Html: page.text,
    activeStepAfterStep4: activeStep(page.text)
  }
}];

const prep = $('Fill Steps 1-4').item.json;
const solver = $('Set Captcha Solver Config').item.json || {};
const antragConfig = $('Set Antrag Config').item.json || {};
const data = prep.data || {};
const html = prep.pageAfterStep4Html || '';

function extractSiteKey(pageHtml) {
  const m = pageHtml.match(/<div class=\"frc-captcha\"[^>]*data-sitekey=\"([^\"]+)\"/i);
  return m ? m[1] : '';
}

if (data.captchaToken && String(data.captchaToken).trim()) {
  return [{ json: { needsSolver: false, captchaToken: String(data.captchaToken).trim(), captchaSource: 'input' } }];
}

if (solver.captchaRequired === false) {
  return [{ json: { needsSolver: false, captchaToken: '', captchaSource: 'none' } }];
}

if (!solver.enabled) {
  throw new Error('workflow_error: Captcha ist erforderlich, aber Solver ist deaktiviert.');
}

const sitekey = String(data.captchaSolver?.siteKey || solver.siteKey || extractSiteKey(html) || '').trim();
if (!sitekey) {
  throw new Error('workflow_error: FriendlyCaptcha sitekey konnte nicht ermittelt werden.');
}

const pageurl = String(antragConfig.startUrl || prep.formUrl || '').trim();
if (!pageurl) {
  throw new Error('workflow_error: pageurl fehlt fuer SolveCaptcha.');
}

return [{
  json: {
    needsSolver: true,
    sitekey,
    pageurl
  }
}];

const r = $json || {};
if (Number(r.status) !== 1 || !r.request) {
  throw new Error(`workflow_error: SolveCaptcha in.php Fehler: ${JSON.stringify(r).slice(0, 260)}`);
}
return [{ json: { captchaId: String(r.request) } }];

const r = $json || {};
if (Number(r.status) === 1 && r.request) {
  return [{ json: { captchaToken: String(r.request), captchaSource: 'solvecaptcha' } }];
}
if (String(r.request || '').toUpperCase() === 'CAPCHA_NOT_READY') {
  throw new Error('workflow_error: SolveCaptcha antwortet CAPCHA_NOT_READY. Erhoehe pollDelaySeconds oder fuehre erneut aus.');
}
throw new Error(`workflow_error: SolveCaptcha res.php Fehler: ${JSON.stringify(r).slice(0, 260)}`);

const prep = $('Fill Steps 1-4').item.json;
const tokenInput = $json || {};

const jar = prep.jar || {};
const FORM_URL = prep.formUrl;
const pageHtml = prep.pageAfterStep4Html || '';
const token = String(tokenInput.captchaToken || '').trim();
const captchaSource = String(tokenInput.captchaSource || 'unknown');

if (!FORM_URL) {
  throw new Error('workflow_error: formUrl aus Step 1-4 fehlt.');
}
if (!token) {
  throw new Error('workflow_error: Captcha-Token fehlt. Abbruch vor Absenden.');
}

const httpRequest = this.helpers.httpRequest.bind(this.helpers);

function parseSetCookie(cookieLine) {
  const first = String(cookieLine || '').split(';')[0];
  const idx = first.indexOf('=');
  if (idx === -1) return null;
  return {
    name: first.slice(0, idx).trim(),
    value: first.slice(idx + 1).trim()
  };
}

function cookieHeader(localJar) {
  return Object.entries(localJar)
    .map(([k, v]) => `${k}=${v}`)
    .join('; ');
}

function extractSetCookies(headers) {
  const raw = headers?.['set-cookie'] ?? headers?.['Set-Cookie'];
  if (!raw) return [];
  return Array.isArray(raw) ? raw : [String(raw)];
}

function shortHtmlSnippet(html) {
  return String(html || '')
    .replace(/\s+/g, ' ')
    .slice(0, 260);
}

function activeStep(html) {
  const m = html.match(/<li class="active">([\s\S]*?)<\/li>/i);
  if (!m) return 'unknown';
  return m[1].replace(/<[^>]+>/g, '').trim();
}

function extractInputValues(html) {
  const out = {};
  const tagRe = /<input\b[^>]*>/gi;
  let tagMatch;
  while ((tagMatch = tagRe.exec(html)) !== null) {
    const tag = tagMatch[0];
    const nameMatch = tag.match(/\bname\s*=\s*"([^"]+)"/i);
    if (!nameMatch) continue;
    const valueMatch = tag.match(/\bvalue\s*=\s*"([^"]*)"/i);
    out[nameMatch[1]] = valueMatch ? valueMatch[1] : '';
  }
  return out;
}

async function submitMultipart({ url, formData, localJar }) {
  const headers = {
    'User-Agent': 'Mozilla/5.0 (Linux; Android 6.0; Nexus 5 Build/MRA58N) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Mobile Safari/537.36',
    Accept: 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
    Origin: 'https://verein.dfbnet.org',
    Referer: FORM_URL
  };

  const cookie = cookieHeader(localJar);
  if (cookie) headers.Cookie = cookie;

  const response = await httpRequest({
    method: 'POST',
    url,
    headers,
    formData,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  });

  const setCookies = extractSetCookies(response.headers);
  for (const line of setCookies) {
    const parsed = parseSetCookie(line);
    if (parsed) localJar[parsed.name] = parsed.value;
  }

  const text = typeof response.body === 'string' ? response.body : String(response.body || '');
  return {
    status: Number(response.statusCode || 0),
    text,
    headers: response.headers || {}
  };
}

const inputs = extractInputValues(pageHtml);
const iStep = String(inputs.iStep || '').trim();
if (!iStep) {
  throw new Error('workflow_error: iStep konnte aus Schritt 4 nicht ermittelt werden.');
}

const payload = {
  'frc-captcha-solution': token,
  iStep,
  iOperation: '1'
};

const submitResult = await submitMultipart({ url: FORM_URL, formData: payload, localJar: jar });
if (submitResult.status < 200 || submitResult.status >= 400) {
  throw new Error(
    `Schritt 5 (Absenden) fehlgeschlagen: HTTP ${submitResult.status}, iStep=${iStep}, keys=${Object.keys(payload).join(',')}, snippet=${shortHtmlSnippet(submitResult.text)}`
  );
}

const finalStep = activeStep(submitResult.text);
if (finalStep === 'Kontrolle/Absenden' || finalStep === 'unknown') {
  throw new Error(
    `Absenden fehlgeschlagen, finalStep=${finalStep}, iStep=${iStep}, keys=${Object.keys(payload).join(',')}, snippet=${shortHtmlSnippet(submitResult.text)}`
  );
}

return [{
  json: {
    success: true,
    message: 'Mitgliedsantrag wurde abgeschickt.',
    captchaSource,
    finalStep,
    submittedWithoutCaptcha: false,
    statusCode: submitResult.status
  }
}];
